/**
 * Higher order function that transform a `getLabelTransform` to the <text /> anchor props.
 */
export const createGetLabelTextAnchors = getLabelTransform => (px, py, tickLabelPosition) => {
  const {
    verticalAlign,
    horizontalAlign
  } = getLabelTransform(px, py, tickLabelPosition);
  let textAnchor;
  let dominantBaseline;
  switch (verticalAlign) {
    case 'start':
      dominantBaseline = 'hanging';
      break;
    case 'middle':
      dominantBaseline = 'middle';
      break;
    case 'end':
    default:
      dominantBaseline = 'auto';
      break;
  }
  switch (horizontalAlign) {
    case 'start':
      textAnchor = 'start';
      break;
    case 'middle':
      textAnchor = 'middle';
      break;
    case 'end':
    default:
      textAnchor = 'end';
      break;
  }
  return {
    textAnchor,
    dominantBaseline
  };
};